<template scoped>
    <div class="container">
        <div class="row">
            <div class="col-12 col-md-12">
                <div class="card my-3 d-flex flex-column">
                <div class="row">
                    <div class="col-md-8">
                    <img :src="productdetail.productImg" class="img-fluid rounded-start w-100" alt="...">
                    </div>
                    <div class="col-md-4 d-flex flex-column">
                    <div class="card-body flex-grow-1">
                        <h5 class="card-title border-bottom">{{productdetail.productName}}</h5>
                        <p class="card-text">{{ productdetail.productDesc }}</p>
                    </div>
                    <div class="w-100 text-end p-3 row">
                        <h5>價格：{{ productdetail.productPrice }}</h5>
                        <button @click="addToCart" class="btn btn-secondary" style="height: 100px;">點我加入購物車</button>
                    </div>
                    </div>
                </div>
                </div>
            </div>
        </div>
    </div>

    <div class="container-fluid bg-secondary bg-gradient p-5" style="height:500px;">
        <div class="container">
            商品材質、風格、詳細說明
            
        </div>
    </div>

    <div class="container-fluid" style="height:500px;">
     <div class="row ">
        <div class="col-6 col-md-6 ">
            <div class="card my-3 d-flex flex-column">
                product description
            </div>

        </div>
        <div class="col-6 col-md-6 g-1  ">
            <div class="p-2">
                <img :src="productdetail.productImg" class="img-fluid rounded-start w-100 d-block " alt="...">
            </div>
        </div>
     </div>   
    </div>


    <!-- 加入購物車成功提示 -->
    <div class="position-fixed bottom-0 end-0 p-3">
        <div id="toast" class="toast" role="alert" aria-live="assertive" aria-atomic="true">
            <div class="toast-header">
            <strong class="me-auto">購物車提示</strong>
            <button type="button" class="btn-close" data-bs-dismiss="toast" aria-label="Close"></button>
            </div>
            <div class="toast-body">
            商品成功加入購物車！
            </div>
        </div>
    </div>



</template>

<script >
import {ref,onMounted} from 'vue'
import { useCartItemsStore } from '@/store/cartItems'
import bootstrap from '../../../node_modules/bootstrap/dist/js/bootstrap.js'
import axios from 'axios'
export default {
  name:'ProductDetail',
  setup(){
    const url =window.location.href
    const urlParams = new URL(url)
    const param = urlParams.searchParams.get("productid")
    const productDetailId=ref(param)
    let productdetail=ref({})
    let cartItems = useCartItemsStore()

    function addToCart(){
        var myToast = new bootstrap.Toast(document.getElementById('toast'));

        let product = {
                id:productdetail.value.id,
                productName:productdetail.value.productName,
                productPrice:productdetail.value.productPrice,
                productImg:productdetail.value.productImg,
                productDesc:productdetail.value.productDesc,
                quantity:1
            }


        if(localStorage.getItem('cart')===null){
            let shoppingCart = {
                items:[]
            }
            shoppingCart.items.push(product)
            localStorage.setItem('cart',JSON.stringify(shoppingCart))
        }else{
            let cart = JSON.parse(localStorage.getItem('cart'))
            let sameProduct =false
            for(var i=0;i<cart.items.length;i++){
                if(cart.items[i].id ===productdetail.value.id){
                    cart.items[i].quantity ++
                    localStorage.setItem('cart',JSON.stringify(cart))
                    sameProduct==true
                    myToast.show();
                    return
                }
            }
            if(!sameProduct){
                cart.items.push(product)
                localStorage.setItem('cart',JSON.stringify(cart))
                cartItems.cartTrigger()
            }
        }

        myToast.show();
        
    }


    onMounted(() => {
        axios.get(`/getproductdetail?productid=${param}`).then(
            response =>{
                productdetail.value=response.data
                console.log('請求發送成功')
                console.log(response.data)
            }
        ).catch(
            error =>{
                console.log(error.message)
            }
        )
    })

    return {
        productDetailId,
        productdetail,
        addToCart
    }
  }
}
</script>

